#!/usr/bin/env python3 """ LLM Wiki CLI - Command-line interface """ import argparse import sys from pathlib import Path from llm_wiki import LLMWiki, WikiConfig def cmd_init(args): """Initialize a new wiki""" wiki = LLMWiki(args.directory) print(f"✅ Wiki initialized: {args.directory}") print(f"   Raw sources: {wiki.config.raw_dir}/") print(f"   Wiki output: {wiki.config.wiki_dir}/") print(f"   Schema: {wiki.config.schema_file}") print(f"\nNext steps:") print(f"  1. Add documents to {wiki.config.raw_dir}/") print(f"  2. Run 'llm-wiki scan' to see pending sources") print(f"  3. Process sources with your LLM") def cmd_status(args): """Show wiki status""" wiki = LLMWiki(args.directory) status = wiki.status() print("📊 Wiki Status") print(f" Base Directory: {status['base_dir']}") print(f" Processed Sources: {status['processed_sources']}") print(f" Pending Sources: {status['unprocessed_sources']}") print(f" Wiki Pages:") print(f" - Entities: {status['wiki_pages']['entities']}") print(f" - Concepts: {status['wiki_pages']['concepts']}") print(f" - Summaries: {status['wiki_pages']['summaries']}") print(f" - Total: {status['wiki_pages']['total']}") print(f" Index: {'✅' if status['has_index'] else '❌'}") print(f" Log: {'✅' if status['has_log'] else '❌'}") print(f" Schema: {'✅' if status['has_schema'] else '❌'}") def cmd_scan(args): """Scan for unprocessed sources""" wiki = LLMWiki(args.directory) unprocessed = wiki.get_unprocessed_sources() print(f"📄 Scan Results:") print(f" Pending sources: {len(unprocessed)}") for doc in unprocessed: print(f" - {doc.metadata['name']} ({doc.metadata['size']} bytes, hash: {doc.hash})") if not unprocessed: print(" (No pending sources found)") def cmd_lint(args): """Run health check""" wiki = LLMWiki(args.directory) issues = wiki.lint() print(f"🔍 Health Check:") if not issues: print(" ✅ No issues found") else: for issue in issues: severity = issue['severity'].upper() print(f" [{severity}] {issue['type']}: {issue['message']}") def cmd_update_index(args): """Update wiki index""" wiki = LLMWiki(args.directory) wiki.update_index() print("✅ Index updated") def cmd_create(args): """Create a wiki page""" wiki = LLMWiki(args.directory) # Read content from stdin or file if args.file: content = Path(args.file).read_text(encoding="utf-8") else: print("Enter page content (Ctrl+D to finish):") content = sys.stdin.read() page_path = wiki.create_page(args.type, args.name, content) print(f"✅ Created: {page_path}") def cmd_mark(args): """Mark source as processed""" wiki = LLMWiki(args.directory) sources = wiki.get_unprocessed_sources() for source in sources: if source.hash.startswith(args.hash): wiki.mark_source_processed(source) print(f"✅ Marked as processed: {source.metadata['name']}") return print(f"❌ Source not found: {args.hash}") def main(): """CLI entry point""" parser = argparse.ArgumentParser( description="LLM Wiki - Incremental knowledge base system", formatter_class=argparse.RawDescriptionHelpFormatter, epilog=""" Examples: llm-wiki init my-wiki Create a new wiki llm-wiki status Show wiki status llm-wiki scan Scan for pending sources llm-wiki lint Run health check llm-wiki create entity "Andrej Karpathy" Create entity page """, ) parser.add_argument("--version", action="version", version="%(prog)s 0.1.0") subparsers = parser.add_subparsers(dest="command", help="Available commands") # init parser_init = subparsers.add_parser("init", help="Initialize a new wiki") parser_init.add_argument("directory", default=".", nargs="?", help="Wiki directory (default: current)") parser_init.set_defaults(func=cmd_init) # status parser_status = subparsers.add_parser("status", help="Show wiki status") parser_status.add_argument("directory", default=".", nargs="?", help="Wiki directory") parser_status.set_defaults(func=cmd_status) # scan parser_scan = subparsers.add_parser("scan", help="Scan for pending sources") parser_scan.add_argument("directory", default=".", nargs="?", help="Wiki directory") parser_scan.set_defaults(func=cmd_scan) # lint parser_lint = subparsers.add_parser("lint", help="Run health check") parser_lint.add_argument("directory", default=".", nargs="?", help="Wiki directory") parser_lint.set_defaults(func=cmd_lint) # update-index parser_update = subparsers.add_parser("update-index", help="Update wiki index") parser_update.add_argument("directory", default=".", nargs="?", help="Wiki directory") parser_update.set_defaults(func=cmd_update_index) # create parser_create = subparsers.add_parser("create", help="Create a wiki page") parser_create.add_argument("type", choices=["entity", "concept", "summary"], help="Page type") parser_create.add_argument("name", help="Page name") parser_create.add_argument("--file", "-f", help="Read content from file") parser_create.add_argument("directory", default=".", nargs="?", help="Wiki directory") parser_create.set_defaults(func=cmd_create) # mark parser_mark = subparsers.add_parser("mark", help="Mark source as processed") parser_mark.add_argument("hash", help="Source hash (prefix match)") parser_mark.add_argument("directory", default=".", nargs="?", help="Wiki directory") parser_mark.set_defaults(func=cmd_mark) args = parser.parse_args() if args.command is None: parser.print_help() sys.exit(1) args.func(args) if __name__ == "__main__": main()
